// // This module is designed to shift its contents to the left on each rising edge of the clock signal.
module shift_register(
    input wire clk,
    input wire rst_n,
    input wire d,
    output reg [7:0] q
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        q <= 8'd0;
    else
        q <= {d, q[7:1]};
end

endmodule
